import{_ as o,o as e,c as t,ae as s}from"./chunks/framework.CiBL6oPQ.js";const u=JSON.parse('{"title":"Database & Migrations","description":"","frontmatter":{},"headers":[],"relativePath":"features/database.md","filePath":"features/database.md"}'),r={name:"features/database.md"};function n(i,a,l,d,g,c){return e(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="database-migrations" tabindex="-1">Database &amp; Migrations <a class="header-anchor" href="#database-migrations" aria-label="Permalink to &quot;Database &amp; Migrations&quot;">​</a></h1><p>Robust data management is a core feature of this generator. We support both SQL and NoSQL databases with automated migration pipelines.</p><h2 id="supported-databases" tabindex="-1">Supported Databases <a class="header-anchor" href="#supported-databases" aria-label="Permalink to &quot;Supported Databases&quot;">​</a></h2><ul><li><strong>PostgreSQL</strong>: Using <code>pg</code> driver and <strong>Flyway</strong> for SQL migrations.</li><li><strong>MySQL</strong>: Using <code>mysql2</code> driver and <strong>Flyway</strong> for SQL migrations.</li><li><strong>MongoDB</strong>: Using <strong>Mongoose</strong> for schema definition and <code>migrate-mongo</code> for schema migrations.</li></ul><h2 id="sql-migrations-postgresql-mysql" tabindex="-1">SQL Migrations (PostgreSQL/MySQL) <a class="header-anchor" href="#sql-migrations-postgresql-mysql" aria-label="Permalink to &quot;SQL Migrations (PostgreSQL/MySQL)&quot;">​</a></h2><p>Managed via <strong>Flyway</strong> inside the <code>docker-compose.yml</code> lifecycle.</p><ul><li><strong>Location</strong>: SQL files are saved in <code>flyway/sql/</code>.</li><li><strong>Auto-run</strong>: Migrations execute automatically when you run <code>docker-compose up</code>.</li><li><strong>Naming</strong>: <code>V1__initial_schema.sql</code>, <code>V2__add_users_table.sql</code>.</li></ul><h2 id="mongodb-migrations" tabindex="-1">MongoDB Migrations <a class="header-anchor" href="#mongodb-migrations" aria-label="Permalink to &quot;MongoDB Migrations&quot;">​</a></h2><p>Managed via <code>migrate-mongo</code>.</p><ul><li><strong>Config</strong>: <code>migrate-mongo-config.js</code> in the project root.</li><li><strong>Commands</strong>: <ul><li><code>npm run migrate:up</code>: Apply new migrations.</li><li><code>npm run migrate:status</code>: Check migration status.</li></ul></li></ul><h2 id="none-database-mode" tabindex="-1">&quot;None&quot; Database Mode <a class="header-anchor" href="#none-database-mode" aria-label="Permalink to &quot;&quot;None&quot; Database Mode&quot;">​</a></h2><p>If you select <strong>None</strong>, the generator creates a <strong>Mock In-Memory Model</strong>.</p><ul><li><strong>Benefit</strong>: Great for building pure workers (Kafka) or testing logic without needing a running database.</li><li><strong>Structure</strong>: Follows the same repository/service pattern as real databases for seamless future migration.</li></ul>',13)])])}const p=o(r,[["render",n]]);export{u as __pageData,p as default};
